const lead = $input.first().json.body || $input.first().json;

if (!lead.id) throw new Error('lead.id is required');

// Zone-to-advisor assignment matrix
const ADVISOR_MAP = [
  { zones: ['cascais','estoril','sintra','oeiras'], advisor: 'advisor.cascais@agencygroup.pt', name: 'Advisor Cascais/Sintra' },
  { zones: ['chiado','príncipe real','lapa','santos','bairro alto','campo de ourique','estrela','belém'], advisor: 'advisor.lisboa.centro@agencygroup.pt', name: 'Advisor Lisboa Centro' },
  { zones: ['parque das nações','expo','oriente','beato','marvila'], advisor: 'advisor.lisboa.oriental@agencygroup.pt', name: 'Advisor Lisboa Oriental' },
  { zones: ['algarve','vilamoura','quinta do lago','vale do lobo','lagos','faro','albufeira','portimão'], advisor: 'advisor.algarve@agencygroup.pt', name: 'Advisor Algarve' },
  { zones: ['porto','foz','boavista','matosinhos','leça','gaia'], advisor: 'advisor.porto@agencygroup.pt', name: 'Advisor Porto' },
  { zones: ['comporta','troia','alcácer do sal','melides'], advisor: 'advisor.comporta@agencygroup.pt', name: 'Advisor Comporta/Troia' },
  { zones: ['madeira','funchal','câmara de lobos','caniço'], advisor: 'advisor.madeira@agencygroup.pt', name: 'Advisor Madeira' },
  { zones: ['açores','azores','ponta delgada'], advisor: 'advisor.acores@agencygroup.pt', name: 'Advisor Açores' },
];

const SENIOR_ADVISORS = ['advisor.cascais@agencygroup.pt','advisor.algarve@agencygroup.pt','advisor.lisboa.centro@agencygroup.pt'];
const DEFAULT_ADVISOR = 'advisor.geral@agencygroup.pt';

// Find zone match
const haystack = `${lead.cidade ?? ''} ${lead.localizacao ?? ''}`.toLowerCase();
let assigned = DEFAULT_ADVISOR;
let advisorName = 'Advisor Geral';

for (const entry of ADVISOR_MAP) {
  if (entry.zones.some(z => haystack.includes(z))) {
    assigned = entry.advisor;
    advisorName = entry.name;
    break;
  }
}

// High-value override: score >= 80 or price_estimate >= 1M → senior
if ((lead.score >= 80 || (lead.price_estimate >= 1_000_000)) && !SENIOR_ADVISORS.includes(assigned)) {
  assigned = 'senior@agencygroup.pt';
  advisorName = 'Senior Advisor (override por score/valor)';
}

return [{ json: { ...lead, assigned_advisor: assigned, advisor_name: advisorName } }];
